Let's begin by creating the necessary classes and implementing their methods step-by-step.

### Step 1: Define the Board Class

First, we need a class to represent the Checkers board. We will use an 8x8 grid and keep track of pieces' positions and types (normal or king).

```python
from typing import List, Tuple

class PieceType:
    EMPTY = 0
    RED = 1
    BLACK = 2
    RED_KING = 3
    BLACK_KING = 4

class Board:
    def __init__(self):
        self.board: List[List[int]] = [
            [PieceType.EMPTY if (i + j) % 2 == 0 else PieceType.RED for j in range(8)] for i in range(8)
        ]
        self.setup_board()

    def setup_board(self):
        # Place black pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = PieceType.BLACK

        # Place red pieces
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = PieceType.RED

    def print_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece != PieceType.EMPTY else "." for piece in row))
        print()

    def get_piece_type(self, row: int, col: int) -> int:
        return self.board[row][col]

    def move_piece(self, from_row: int, from_col: int, to_row: int, to_col: int):
        # Move piece
        self.board[to_row][to_col] = self.board[from_row][from_col]
        self.board[from_row][from_col] = PieceType.EMPTY

        # Check for capture and promote
        if (self.board[to_row][to_col] == PieceType.RED and to_row == 0) or \
           (self.board[to_row][to_col] == PieceType.BLACK and to_row == 7):
            self.board[to_row][to_col] += 1

    def is_valid_move(self, from_row: int, from_col: int, to_row: int, to_col: int) -> bool:
        piece_type = self.get_piece_type(from_row, from_col)

        # Check if the move is within bounds
        if not (0 <= to_row < 8 and 0 <= to_col < 8):
            return False

        # Check if there's a piece at the starting position
        if self.get_piece_type(from_row, from_col) == PieceType.EMPTY:
            return False

        # Check if the destination is empty or occupied by an opponent
        if self.get_piece_type(to_row, to_col) != PieceType.EMPTY and \
           (self.board[from_row][from_col] % 2 == self.board[to_row][to_col] % 2):
            return False

        # Check for valid non-capturing moves
        direction = -1 if piece_type == PieceType.RED else 1
        if abs(from_col - to_col) == 1 and from_row + direction == to_row:
            return True

        # Check for valid capturing moves
        if abs(from_col - to_col) == 2 and from_row + direction * 2 == to_row:
            capture_mid_row = (from_row + to_row) // 2
            capture_mid_col = (from_col + to_col) // 2
            return self.board[capture_mid_row][capture_mid_col] != PieceType.EMPTY and \
                   abs(from_col - capture_mid_col) == 1

        return False

    def is_game_over(self) -> Tuple[bool, str]:
        # Check for a win by checkmate or stalemate
        red_turn = self.get_piece_type(0, 0) % 2 != 0
        if self.is_king_in_checkmate(red_turn):
            return True, "Checkmate"
        if not any(self.is_valid_move(i, j, i + (1 if piece_type == PieceType.RED else -1), j + k)
                   for i in range(8) for j in range(8)
                   for piece_type in [PieceType.RED, PieceType.BLACK]
                   for k in [-1, 1] if not red_turn and piece_type % 2 != 0 or
                   (red_turn and piece_type % 2 == 0)):
            return True, "Stalemate"
        return False, ""

    def is_king_in_checkmate(self, red_turn: bool) -> bool:
        king_row, king_col = next((i, j) for i in range(8) for j in range(8)
                                    if self.board[i][j] == (PieceType.RED_KING if red_turn else PieceType.BLACK_KING))
        # Check all directions
        for dx in [-1, 0, 1]:
            for dy in [-1, 0, 1]:
                if dx != 0 or dy != 0:
                    if self.is_valid_move(king_row, king_col, king_row + dx, king_col + dy):
                        return False
        return True
```

### Step 2: Define the Game Class

Next, we need a class to manage the game state and handle player moves.

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_turn = PieceType.RED

    def start_game(self):
        print("Welcome to Checkers!")
        while True:
            self.board.print_board()
            from_pos, to_pos = input(f"Player {self.current_turn} move (e.g., 0-7): ").split("-")
            from_row, from_col = int(from_pos[0]), int(from_pos[1])
            to_row, to_col = int(to_pos[0]), int(to_pos[1])

            if self.board.is_valid_move(from_row, from_col, to_row, to_col):
                self.board.move_piece(from_row, from_col, to_row, to_col)
                if self.board.is_game_over()[0]:
                    self.board.print_board()
                    print(self.board.is_game_over()[1])
                    break
                self.current_turn = PieceType.RED if self.current_turn == PieceType.BLACK else PieceType.BLACK
            else:
                print("Invalid move. Please try again.")
```

